#include <stdint.h>
#include <ctype.h>

int parse_int32(const char *s, int32_t *out)
{
    if (s == NULL || out == NULL)
        return 0;

    /* skip leading whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s == '\0')
        return 0;

    /* detect sign */
    int sign = 1;
    if (*s == '-') {
        sign = -1;
        s++;
    } else if (*s == '+') {
        s++;
    }

    if (*s == '\0')
        return 0;

    /* parse digits */
    int32_t acc = 0;
    int32_t const hi = sign > 0 ? INT32_MAX : INT32_MIN;
    int32_t const lo = hi / 10;
    int32_t const rem = hi % 10;

    while (*s != '\0') {
        /* reject trailing non-digits */
        if (!isdigit((unsigned char)*s))
            return 0;

        int digit = *s - '0';

        /* check overflow before multiplying and adding */
        if (sign > 0) {
            if (acc > lo || (acc == lo && digit > rem))
                return 0;
        } else {
            /* for negative: INT32_MIN is -2147483648 */
            int32_t neg_hi = -INT32_MAX;
            int32_t neg_lo = neg_hi / 10;
            int32_t neg_rem = neg_hi % 10;
            if (acc > -neg_lo || (acc == -neg_lo && digit > -neg_rem))
                return 0;
        }

        acc = acc * 10 + digit;
        s++;
    }

    /* skip trailing whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s != '\0')
        return 0;

    *out = sign * acc;
    return 1;
}

